"use strict";(()=>{const r=()=>{if(window.matchMedia("(pointer: coarse)").matches||window.matchMedia("(prefers-reduced-motion: reduce)").matches)return;const o=document.querySelectorAll(".glass-glow");if(o.length===0)return;let n=-9999,s=-9999,e=!1;document.addEventListener("mousemove",a=>{n=a.clientX,s=a.clientY,e||(e=!0,requestAnimationFrame(()=>{e=!1;for(const t of o){const c=t.getBoundingClientRect();t.style.setProperty("--glow-x",`${Math.round(n-c.left)}px`),t.style.setProperty("--glow-y",`${Math.round(s-c.top)}px`)}}))})};document.readyState==="loading"?document.addEventListener("DOMContentLoaded",r):r()})();
